head.script:
scwin.strFromDate;

scwin.currentRow = -1;

scwin.bColorChange = true;
scwin.INTERVAL_KEY_PREFIX = "op_304_01_00b_interval_";
scwin.intervalKey;
scwin.colorChangeTarget = [];

/**
 * event
 * @name onpageload
 * @description 화면로딩시
 */
scwin.onpageload = async function () {
    scwin.strFromDate = $c.date.getServerDateTime("yyyyMMdd");  // 현재년월일을 구한다.

    gr_emp2.setUserData("gridName", "컨테이너출도착");
    ed_dptTime.setValue("0800");
    await $c.sbm.execute(sbm_retreiveLoBranCMD);
    //첫번째 row의 lobranCd으로 acb_logisticsBranch를 설정한다.
    let rowObj = ds_joblevel.getRowJSON(0);
    if (!$c.gus.cfIsNull(rowObj.lobranCd)) {
        acb_logisticsBranch.setValue(rowObj.lobranCd);
    }
    scwin.intervalKey = scwin.INTERVAL_KEY_PREFIX + $c.date.getServerDateTime("yyyyMMddhhmmss");
};

/**
 * event
 * @name onbeforepageunload
 * @description 화면언로드시
 */
scwin.onbeforepageunload = function () {
    $c.util.clearInterval(scwin.intervalKey);
};

/**
 * event
 * @name onUdcCompleted
 * @description
 */
scwin.onUdcCompleted = function () {
    ica_wrkDt.setValue(scwin.strFromDate);
    ica_wrkDt.focus();
    ica_wrkDtTo.setValue(scwin.strFromDate);
    ica_wrkDtTo.focus();

};

/**
 * method
 * @name f_Retrieve2
 * @description
 */
scwin.f_Retrieve2 = async function () {
    let wrkDtData = ica_wrkDt.getValue();
    let wrkDtToData = ica_wrkDtTo.getValue();
    if (wrkDtData > wrkDtToData) {
        await $c.win.alert('조회 일자를 정확하게 입력하세요.');
        return;
    }
    let datDifference = await scwin.cfDaysBetween(wrkDtData, wrkDtToData);
    if (datDifference === undefined) {
        return;
    }
    if (datDifference >= 7) {
        await $c.win.alert('시작일로 7일 까지만 조회 가능 합니다.');
        return;
    }

    dma_retrieve2.setJSON({
        "wrkLobranCd": acb_logisticsBranch.getValue(),
        "wrkDt": ica_wrkDt.getValue(),
        "wrkDtTo": ica_wrkDtTo.getValue(),
        "transRsltsExistYn": acb_transRsltsExistYn.getValue(),
        "cntrNo": ed_cntrNo.getValue().trim(),
        "odrNo": ed_odrNo.getValue().trim(),
        "regId": ed_regId.getValue().trim(),
        "vehclNo": ed_vehclNm.getValue().trim(),
        "copClntNo": ed_copClntNo.getValue().trim(),
    });

    $c.util.clearInterval(scwin.intervalKey);
    $c.sbm.execute(sbm_retrieve2);
};

/**
 * method
 * @name cfDaysBetween
 * @description
 */
scwin.cfDaysBetween = async function (stDt, endDt) {
    let v_daysBetween = 0;
    if (!$c.date.isDate(stDt)) {
        await $c.win.alert("시작일자는 'YYYYMMDD' 형식이어야 합니다.");
    } else if (!$c.date.isDate(endDt)) {
        await $c.win.alert("종료일자는 'YYYYMMDD' 형식이어야 합니다.");
    } else {
        v_daysBetween = $c.date.diffDate(stDt, endDt);
    }
    return v_daysBetween;
};

/**
 * method
 * @name f_checkGridEditable
 * @description
 */
scwin.f_checkGridEditable = async function (row) {
    const rowObj = ds_info2.getRowJSON(row);
    let prevRowObj = ds_info2.getRowJSON(row - 1);
    if (prevRowObj.odrNo == rowObj.odrNo && prevRowObj.cntrSeq == rowObj.cntrSeq) {
        //직도어복화중 실복화단계인 경우 무조건 수정불가.
        if (prevRowObj.realCmpstcrgYn == "2") {
            //직도어 복화중 최초, 최종인 경우만 입력 가능.
        } else if (prevRowObj.realCmpstcrgYn == "1") {
        } else if ((prevRowObj.dptIoMgntYn == 0 && prevRowObj.dptHh.trim() == "") || (prevRowObj.arvIoMgntYn == 0 && prevRowObj.arvHh.trim() == "")) {
            ds_info2.undoRow(row);
            scwin.setGridReadonly(true);
            await $c.gus.cfAlertMsg("이전단계의 실적이 발생하지 않은 상태에서 이후단계의 실적이 발생하면 안됩니다");
            return false;
        }
    }

    if (rowObj.mgntClsYn == 1) {
        ds_info2.undoRow(row);
        scwin.setGridReadonly(true);
        return false;
    }
    scwin.setGridReadonly(false);
    return true;
};

/**
 * method
 * @name f_apply
 * @params {String} value 시간
 * @description 일괄적용
 *  odr_no, cntr_seq가 달라지면 새로운 오더로 인식
 *  1) 출도착없을경우 8시-9시 10시-11시 ...
 *  2) 있는경우 +1시간
 */
scwin.f_apply = async function (value) {
    //사용자 입력값
    let valhh = $c.num.parseInt(value.substring(0, 2));
    let valmm = value.substring(2, 4).trim();
    //그리드 데이터값
    let Dhr, Dmn, Ahr;
    //그리드 데이터값
    let hh;
    let mn;
    let rowObj = null;
    let prevRowObj = null;
    const rowCnt = ds_info2.getRowCount();

    for (let row = 0; row < rowCnt; ++row) {
        prevRowObj = rowObj;
        rowObj = ds_info2.getRowJSON(row);
        Dhr = $c.num.parseInt(rowObj.dptHh.substring(0, 2));
        Dmn = rowObj.dptHh.substring(2, 4);
        Ahr = $c.num.parseInt(rowObj.arvHh.substring(0, 2));

        //출발일시/도착일시가 없는게 있는경우만 진행하기
        if (Dhr == "" || isNaN(Dhr) || Ahr == "" || isNaN(Ahr)) {
            //odrNo cntrSeq 가 같은 앞 데이터가 있는 경우는 앞전 거+1시간 하기
            if (prevRowObj !== null && (prevRowObj.odrNo == rowObj.odrNo) && (prevRowObj.cntrSeq == rowObj.cntrSeq)) {
                scwin.f_setData(row, prevRowObj, rowObj);
                rowObj = ds_info2.getRowJSON(row);
            } else {    //새로운 odrNo&&cntrSeq인 경우  ed_dptTime의 값을 셋팅
                //기존에 따르던 flow 추가하기 OnRowPosChanged(row)에 있는 로직 실행
                if (!await scwin.f_checkGridEditable(row)) {
                    continue;
                }

                //기존값이 없는경우 사용자 설정값 셋팅
                if (Dhr == "" || isNaN(Dhr)) {
                    hh = valhh;
                    mn = valmm;
                } else {
                    hh = Dhr;
                    mn = Dmn;
                }

                if (scwin.f_checkColValue(row, rowObj, "dptHh")) {
                    if (hh < 10) {
                        ds_info2.setCellData(row, "dptHh", "0" + (hh) + mn);
                    } else {
                        ds_info2.setCellData(row, "dptHh", (hh) + mn);
                    }
                }
                rowObj = ds_info2.getRowJSON(row);

                if (scwin.f_checkColValue(row, rowObj, "arvHh")) {
                    if (hh < 9) {
                        ds_info2.setCellData(row, "arvHh", "0" + (hh + 1) + mn);
                    } else {
                        ds_info2.setCellData(row, "arvHh", (hh + 1) + mn);
                    }
                }
                rowObj = ds_info2.getRowJSON(row);
            }
        }//end-출도착일시 없는경우
    }//end-for
};

/**
 * method
 * @name f_setData
 * @description 앞데이터의 odrNo cntrSeq 가 현재꺼랑 같은경우  앞전 거+1시간 하기
 */
scwin.f_setData = function (row, prevRowObj, rowObj) {
    let dpt = $c.num.parseInt(rowObj.dptHh.substring(0, 2));
    let avr = $c.num.parseInt(rowObj.arvHh.substring(0, 2));
    if (scwin.f_checkColValue(row, rowObj, "dptHh")) {
        if (dpt == "" || isNaN(dpt)) {
            let DdtYMD = prevRowObj.arvDt;
            let Ahr = $c.num.parseInt(prevRowObj.arvHh.substring(0, 2));
            let AMn = prevRowObj.arvHh.substring(2, 4);
            if (Ahr >= 0 && Ahr < 23) {
                if (Ahr < 9) {
                    ds_info2.setCellData(row, "dptHh", "0" + (Ahr + 1) + AMn);
                    if (prevRowObj.arvDt > rowObj.dptDt) {
                        ds_info2.setCellData(row, "dptDt", DdtYMD);
                    }
                } else {
                    ds_info2.setCellData(row, "dptHh", (Ahr + 1) + AMn);
                    if (prevRowObj.arvDt > rowObj.dptDt) {
                        ds_info2.setCellData(row, "dptDt", DdtYMD);
                    }
                }
            } else {
                let param1 = $c.date.addDate(DdtYMD, 1);
                ds_info2.setCellData(row, "dptDt", param1);
                ds_info2.setCellData(row, "dtpHh", "00" + AMn);
            }
        }
    }
    //위에서 값 변경해서 새로고침
    rowObj = ds_info2.getRowJSON(row);

    if (scwin.f_checkColValue(row, rowObj, "arvHh")) {
        if (avr == "" || isNaN(avr)) {
            scwin.fillArvDthhCell(row, rowObj);
        }
    }
};

/**
 * method
 * @name fillArvDthhCell
 * @description 지정한 row의 도착일자, 도착일시 값 계산해서 채워넣기
 */
scwin.fillArvDthhCell = function (row, rowObj) {
    let Dhr = $c.num.parseInt(rowObj.dptHh.substring(0, 2));
    let DMn = rowObj.dptHh.substring(2, 4);
    let AdtYMD = rowObj.dptDt;
    if (Dhr >= 0 && Dhr < 23) {
        if (Dhr < 9) {
            ds_info2.setCellData(row, "arvHh", "0" + (Dhr + 1) + DMn);
            if (rowObj.dptDt > rowObj.arvDt) {
                ds_info2.setCellData(row, "arvDt", AdtYMD);
            }
        } else {
            ds_info2.setCellData(row, "arvHh", (Dhr + 1) + DMn);
            if (rowObj.dptDt > rowObj.arvDt) {
                ds_info2.setCellData(row, "arvDt", AdtYMD);
            }
        }
    } else {
        let param1 = $c.date.addDate(AdtYMD, 1);
        ds_info2.setCellData(row, "arvDt", param1);
        ds_info2.setCellData(row, "arvHh", "00" + DMn);
    }
};

/**
 * method
 * @name f_checkColValue
 * @description OnRowPosChanged(row) OnColumnPosChanged(row,colid)보고 copy
 *  return true일때만 진행가능
 */
scwin.f_checkColValue = function (row, rowObj, colid) {
    if (colid === "dptHh") {
        if (rowObj.cntrNo == "" || rowObj.dptDt == "" || rowObj.dptIoMgntYn == 1) {
            ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
            gr_emp2.setColumnReadOnly(colid, true);
            return false;
        }

        if (rowObj.realCmpstcrgYn == "2") {
            ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
            gr_emp2.setColumnReadOnly(colid, true);
            return false;
        } else if (rowObj.realCmpstcrgYn == "1" && rowObj.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR && rowObj.wrkStpCd == DsConstants.WRK_STP_CD_RETRV) {
            gr_emp2.setColumnReadOnly(colid, true);
            return false;
        }
        gr_emp2.setColumnReadOnly(colid, false); //Any

        // 6C09 DPCTCY 6C01 BPTCY
        if (rowObj.dptWrkPlCd == "6C09" || rowObj.dptWrkPlCd == "6C01") {
            gr_emp2.setColumnReadOnly("dptHh", true);
            gr_emp2.setColumnReadOnly("dptDt", true);
            return false;
        }
    } else if (colid === "arvHh") {
        if (rowObj.cntrNo == "") {
            ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
            gr_emp2.setColumnReadOnly(colid, true);
            return false;
        }

        if (rowObj.dptDt == "" || rowObj.dptHh == "") {
            if (rowObj.realCmpstcrgYn == "1") {  //직도어 복화중 최초, 최종 단계인 경우 입력 가능.
                gr_emp2.setColumnReadOnly(colid, false); //Any
            } else if (rowObj.realCmpstcrgYn == "2") {
                gr_emp2.setColumnReadOnly(colid, true); //직도어 복화중 실복화 단계인 경우 입력불가.
                return false;
            } else {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                if (rowObj.dptIoMgntYn == 0) {
                } else {
                }
                gr_emp2.setColumnReadOnly(colid, true);
                return false;
            }
        }

        if ((rowObj.arvIoMgntYn == 0 && rowObj.arvDt == "") || rowObj.arvIoMgntYn == 1) {
            ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
            gr_emp2.setColumnReadOnly(colid, true);
            return false;
        }

        if (rowObj.realCmpstcrgYn == "2") {
            gr_emp2.setColumnReadOnly(colid, true); //직도어 복화중 실복화 단계인 경우 입력불가.
            return false;
        } else {
            gr_emp2.setColumnReadOnly(colid, false); //Any
        }

        // 6C09 DPCTCY 6C01 BPTCY
        if (rowObj.arvWrkPlCd == "6C09" || rowObj.arvWrkPlCd == "6C01") {
            gr_emp2.setColumnReadOnly("arvHh", true);
            gr_emp2.setColumnReadOnly("arvDt", true);
            return false;
        }
    }

    return true;
};

/**
 * method
 * @name f_applyDel
 * @description
 */
scwin.f_applyDel = function () {
    let allData = ds_info2.getAllJSON();
    for (let row = allData.length - 1; row >= 0; --row) {
        let rowObj = allData[row];
        if (rowObj.dptHh.substring(0, 2) != "") {
            ds_info2.setCellData(row, "dptHh", "");
        }
        if (rowObj.arvHh.substring(0, 2) != "") {
            ds_info2.setCellData(row, "arvHh", "");
        }
    }//end-for
};

/**
 * method
 * @name f_Save
 * @description 저장
 */
scwin.f_Save = async function () {
    await scwin.f_cntrSeqSearch(gr_emp2.getFocusedRowIndex());
    if (!ds_info2.getModifiedIndex().length) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["Data"]);
        return;
    }
    if (!await $c.gus.cfValidate([gr_emp2])) {
        return;
    }

    let allData = ds_info2.getAllJSON();
    let rowObj = null;
    let nextRowObj = null;
    let chkRowObj = null;
    // 출발일시 from ~ to 체크
    for (let idx = 0; idx < allData.length; ++idx) {
        rowObj = allData[idx];
        if (idx < allData.length - 1) {
            nextRowObj = allData[idx + 1];
            if (((rowObj.dptIoMgntYn == 0 && rowObj.dptHh.trim() == "") || (rowObj.arvIoMgntYn == 0 && rowObj.arvHh.trim() == ""))
                && ((nextRowObj.odrNo == rowObj.odrNo) && (nextRowObj.cntrSeq == rowObj.cntrSeq))   // 다음번 odrno와    cntrSeq가 같을때만 체크
                && (nextRowObj.dptHh.trim() != "" || nextRowObj.arvHh.trim() != "")) {
                if (nextRowObj.realCmpstcrgYn != "1") {
                    let v_lastRow = 0;
                    //201706 현재 변경하려는 작업단계 lastlow를 구해오자
                    for (let j = allData.length - 1; j >= idx; --j) {
                        chkRowObj = allData[j];
                        if (chkRowObj.rowStatus == "U" && chkRowObj.odrNo == rowObj.odrNo && chkRowObj.cntrSeq == rowObj.cntrSeq) {
                            v_lastRow = j;
                            break;
                        }
                    }
                    await $c.gus.cfAlertMsg((v_lastRow + 1) + "번째줄 단계의 실적이 발생하지 않은 상태에서 이후단계의 실적이 발생하면 안됩니다");
                    return;
                }
            }
        }

        if (rowObj.rowStatus === "U") { //수정
            //경기지사인경우 샤시번호 필수입력..
            if (acb_logisticsBranch.getValue() == "4BB" && !$c.gus.cfIsNull(rowObj.cntrNo)
                && (!$c.gus.cfIsNull(rowObj.dptHh.trim()) || !$c.gus.cfIsNull(rowObj.arvHh.trim()))
                && $c.gus.cfIsNull(rowObj.chassisNo.trim())) {
                await $c.gus.cfAlertMsg((idx + 1) + "번째 행의 샤시번호를 입력해야 합니다.");
                return;
            }

            if (rowObj.cntrNo == "" && (rowObj.dptHh.trim() != "" || rowObj.arvHh.trim() != "")) {
                await $c.gus.cfAlertMsg((idx + 1) + "번째 행에서 컨테이너번호가 없는 상태에서 출도착일시가 입력되었습니다");
                return;
            }

            if (rowObj.wrkStpCd != DsConstants.WRK_STP_CD_SHUTTLE && rowObj.dptDt != "" && rowObj.dptHh != "" && rowObj.arvDt != "" && rowObj.arvHh != "") {
                if (!scwin.f_DifferBetweenDate(rowObj.dptDt + rowObj.dptHh, rowObj.arvDt + rowObj.arvHh)) {
                    await $c.gus.cfAlertMsg((idx + 1) + "번째 데이타에서 시작일자가 종료일자 이전이어야 합니다");
                    return;
                }
            }
        }
    }

    for (let idx = 0; idx < allData.length; ++idx) {
        rowObj = allData[idx];
        if (rowObj.socYn == "1" && rowObj.odrKndCd != DsConstants.ODR_KND_CD_OFF_HIRE_ODR) {
            await $c.gus.cfAlertMsg((idx + 1) + "번째 반출불가\n반출제어 대상 컨테이너 입니다.\nLINE 담당자에게 확인바랍니다.\n");
            return false;
        }
    }

    //원본값을 세팅
    for (let idx = 0; idx < allData.length; ++idx) {
        if (allData[idx].rowStatus === "U") { //수정
            ds_info2.setCellData(idx, "orgCntrNo", ds_info2.getOriginalCellData(idx, "cntrNo"));
            ds_info2.setCellData(idx, "orgCntrSizCd", ds_info2.getOriginalCellData(idx, "cntrSizCd"));
            ds_info2.setCellData(idx, "orgCntrTypCd", ds_info2.getOriginalCellData(idx, "cntrTypCd"));
            ds_info2.setCellData(idx, "orgSealNo", ds_info2.getOriginalCellData(idx, "sealNo"));
            ds_info2.setCellData(idx, "orgDptDt", ds_info2.getOriginalCellData(idx, "dptDt"));
            ds_info2.setCellData(idx, "orgDptHh", ds_info2.getOriginalCellData(idx, "dptHh"));
            ds_info2.setCellData(idx, "orgArvDt", ds_info2.getOriginalCellData(idx, "arvDt"));
            ds_info2.setCellData(idx, "orgArvHh", ds_info2.getOriginalCellData(idx, "arvHh"));
            ds_info2.setCellData(idx, "orgChassisNo", ds_info2.getOriginalCellData(idx, "chassisNo"));
        }
    }

    if (await scwin.f_RowDifferBetweenDate(allData)) {
        return;
    }

    // -------------------------------------------------------------
    for (let idx = 0; idx < allData.length - 1; ++idx) {
        rowObj = allData[idx];
        if (rowObj.cntrNo == "") {
            continue;
        }
        for (let j = idx + 1; j < allData.length; ++j) {
            chkRowObj = allData[j];
            if (chkRowObj.cntrNo == "") {
                continue;
            }
            if (rowObj.wrkPathSeq == chkRowObj.wrkPathSeq) {
                if (rowObj.odrNo == chkRowObj.odrNo && chkRowObj.cntrNo != rowObj.cntrNo) {
                    await $c.win.alert((j + 1) + "번째 줄에 같은 작업경로에 다른 컨테이너번호가 있습니다.");
                    ds_info2.setCellData(j, "cntrNo", "");
                    return;
                }
            } else {
                if (chkRowObj.cntrNo !== rowObj.cntrNo) {
                    continue;
                }

                if (rowObj.odrNo == chkRowObj.odrNo) {
                    await $c.win.alert((j + 1) + "번째 줄에 다른 작업경로에 같은 컨테이너번호가 있습니다.");
                    ds_info2.setCellData(j, "cntrNo", "");
                    return;
                }

                // 복화종류=컴바인 같은 작업경로순번인데 같은 컨테이너번호일 경우.
                if (rowObj.cmpstcrgKndCd == "CB" && chkRowObj.cmpstcrgKndCd == "CB") {
                    await $c.win.alert((j + 1) + "번째 줄의 작업지시는 컴바인이므로 컨테이너번호가 달라야 합니다.");
                    ds_info2.setCellData(j, "cntrNo", "");
                    ds_info2.setCellData(j, "dptHh", rowObj.dptHh);
                    ds_info2.setCellData(j, "arvHh", rowObj.arvHh);
                    return;
                }
            }
        }

        if (rowObj.cntrNo != "" && !dscommon.cf_CheckCntrNo(rowObj.cntrNo)) {
            if (!await $c.win.confirm((idx + 1) + "번째 컨테이너 번호는 유효하지 않기 때문에 저장하지  못합니다. 계속진행하시겠습니까?")) {
                return;
            }
        }
    }
    // -------------------------------------------------------------
    if (await scwin.hourNullCheck(allData)) {
        if (await $c.win.confirm(MSG_CM_CRM_001)) {
            $c.util.clearInterval(scwin.intervalKey);
            $c.sbm.execute(sbm_saveEmp);
        }
    }
};

/**
 * method
 * @name f_RowDifferBetweenDate
 * @params {Array} allData 전체 데이터 배열
 * @description 간 일자 체크 함수
 */
scwin.f_RowDifferBetweenDate = async function (allData) {
    let oldArvDt = "";
    let oldArvHh = "";
    let j = null;
    let rowObj = null;
    for (let idx = 1; idx < allData.length; ++idx) {
        j = idx - 1;
        rowObj = allData[idx];
        if (idx == 0 || (allData[j].odrNo != rowObj.odrNo) || (allData[j].cntrSeq != rowObj.cntrSeq)) {
            if (rowObj.arvIoMgntYn == 0) {
                oldArvDt = rowObj.arvDt;
                oldArvHh = rowObj.arvHh;
            } else if (rowObj.dptIoMgntYn == 0) {
                oldArvDt = rowObj.dptDt;
                oldArvHh = rowObj.dptHh;
            } else {
                oldArvDt = "";
                oldArvHh = "";
            }
            continue;
        }

        //i==1이아닐경우
        //201706 오더번호와 컨테이너seq가 같을때만 체크
        if (oldArvHh.trim() != "" && rowObj.dptHh.trim() != "" && allData[j].odrNo == rowObj.odrNo && allData[j].cntrSeq == rowObj.cntrSeq) {
            if (rowObj.rowStatus === "U" && rowObj.wrkStpCd != DsConstants.WRK_STP_CD_SHUTTLE
                && rowObj.dptDt.trim() != "" && rowObj.dptHh.trim() != "" && oldArvDt.trim() != "" && oldArvHh.trim() != ""
                && (rowObj.dptDt.trim() + rowObj.dptHh.trim()) <= (oldArvDt.trim() + oldArvHh.trim())) {
                await $c.gus.cfAlertMsg((idx + 1) + "번째 데이타에서 시작일시가 " + (j + 1) + "번째 종료일시보다  이후 이어야 합니다.");
                return true;
            }
        } else {
            continue;
        }

        if (rowObj.arvIoMgntYn == 0) {
            oldArvDt = rowObj.arvDt;
            oldArvHh = rowObj.arvHh;
        } else if (rowObj.dptIoMgntYn == 0) {
            oldArvDt = rowObj.dptDt;
            oldArvHh = rowObj.dptHh;
        } else {
            oldArvDt = "";
            oldArvHh = "";
        }
    }
    return false;
};

/**
 * method
 * @name hourNullCheck
 * @description
 */
scwin.hourNullCheck = async function () {
    let rowCnt = ds_info2.getRowCount();
    for (i = 0; i < rowCnt; i++) {
        let rowObj = ds_info2.getRowJSON(i);
        if (rowObj.rowStatus == "U") {
            if (rowObj.arvHh == "") {
                ds_info2.setCellData(i, "arvDt", "");
            }
            if (rowObj.dptHh == "") {
                ds_info2.setCellData(i, "dptDt", "");
            }

            if (!dscommon.cf_gidHourNullCheck(rowObj.arvHh)) {
                // gr_emp2.ColSelect = "true";
                await $c.gus.cfAlertMsg((i + 1) + "번째 도착시간을 정확한 시간을 입력하세요");
                gr_emp2.setFocusedCell(i, "arvHh", true);
                return false;
            }
        }
    }
    return true;
};

/**
 * method
 * @name f_DifferBetweenDate
 * @description 출발일시 from ~ to 체크 함수
 */
scwin.f_DifferBetweenDate = function (sDateStr, eDateStr) {
    sDateStr = sDateStr.trim();
    eDateStr = eDateStr.trim();

    if (eDateStr == "00" || sDateStr == "00") {
        return true;
    }
    // 종료일자가 시작일자 이후인지 확인
    if (sDateStr >= eDateStr) {
        return false;
    }
    return true;
};

