/**
 * method
 * @name checkContainerCnt
 * @description 팝업 콜백 함수
 */
scwin.checkContainerCnt = async function (row) {
    let rowObj = ds_info2.getRowJSON(row);
    //당사가 컨관리나 무브먼트를 제공하는 OFF-DOCK 선사(OP420)
    await scwin.f_retrieveCodeList("OP420", rowObj.lineCd);
    if (!$c.gus.cfIsNull(ds_codeInfo.getCellData(0, "col1")) //당사가 컨관리나 무브먼트를 제공하는 OFF-DOCK 선사가 아니고
        && rowObj.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES) {     //자가영업이면
        // 출도착은 작업장 기준으로 처리함...
        // 입력된 컨테이너 번호로 SD404의 MGNT_CLS_YN = 1 인 컨테이너가 있으면 메세지 출력
        await scwin.f_retrieveManagementedContainerCnt(rowObj.cntrNo);
        if (ds_chkContainer.getCellData(0, "cd") != "0") {
            await $c.win.alert("컨테이너 " + rowObj.cntrNo + "는 관리구분이 살아있는 컨테이너가 " + ds_chkContainer.getCellData(0, "cd") + "개 있습니다.\n 관리구분을 수정하시고 작업을 진행하십시오.");
            ds_info2.setCellData(row, "cntrNo", "");
            ds_info2.setCellData(row + 1, "cntrNo", "");
        }
    }
};

