scwin.f_openPopUpOdrNo = async function () {
    let data = [
        ed_cntrNo.getValue().trim(), //컨테이너번호
        "", //오더종류
    ];

    let opts = {
        id: "op_301_02_04p1_popup",
        popupName: "오더검색",
        modal: true,
        type: "browserPopup",  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
        title: "Win pop",  //Layer pop
        width: 820,
        height: 400,
    };
    let rtnList = await $c.win.openPopup("/ui/ds/sd/odrmgnt/odrreg/sd_402_01_31p.xml", opts, data);
    if (rtnList != null) {
        if (rtnList[0] != "N/A") {
            ed_odrNo.setValue(rtnList[0]);  // 오더번호
            ica_wrkDt.setValue("");
        }
    }
};

/**
 * method
 * @name colorChange
 * @description
 */
scwin.startColorChange = function () {
    $c.util.clearInterval(scwin.intervalKey);
    scwin.colorChangeTarget = ds_info2.getUnmatchedIndex("copinoResponse", "", true);
    if (scwin.colorChangeTarget.length) {
        $c.util.setInterval(scwin.colorChange(), { delay: 1000, key: scwin.intervalKey });
    }
};

/**
 * method
 * @name colorChange
 * @description
 */
scwin.colorChange = function () {
    if (scwin.bColorChange) {
        for (let row of scwin.bColorChange) {
            gr_emp2.setCellBackgroundColor(row, 'cntrNo', '#FBCED4');
        }
    } else {
        for (let row of scwin.bColorChange) {
            gr_emp2.setCellBackgroundColor(row, 'cntrNo', '');
        }
    }

    scwin.bColorChange = !scwin.bColorChange;
};

/**
 * event
 * @name sbm_saveEmp_submitdone
 * @description
 */
scwin.sbm_saveEmp_submitdone = async function (e) {
    if (e.responseJSON?.resultDataSet?.length && e.responseJSON.resultDataSet[0].Code == -1) {
        return;
    }
    await $c.gus.cfAlertMsg(MSG_CM_INF_001, [""]);
    const rowCnt = ds_info2.getRowCount();
    //for=ds_info2
    if (!rowCnt) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002, [""]);  //"조회된 데이터가 없습니다.";
    } else {
        gr_emp2.setFocusedCell(0, 0, false);
    }
    tbx_totalRows.setValue(rowCnt);
    scwin.startColorChange();
};

/**
 * event
 * @name sbm_cntrNoSeqInfo_submitdone
 * @description
 */
scwin.sbm_cntrNoSeqInfo_submitdone = function (e) {
    if (e.responseJSON?.resultDataSet?.length && e.responseJSON.resultDataSet[0].Code == -1) {
        return;
    }
    let row = gr_emp2.getFocusedRowIndex();
    if (row < 0) {
        return;
    }
    let data = dma_CntrNoSeqInfo.getJSON();
    ds_info2.setCellData(row, 'cntrNo', data.cntrNo);
    ds_info2.setCellData(row, 'cntrSeq', data.cntrSeq);
    ds_info2.setCellData(row, 'wrkPathSeq', data.wrkPathSeq);
    ds_info2.setCellData(row, 'wrkStpSeq', data.wrkStpSeq);
    ds_info2.setCellData(row, 'arrvlportDtm', data.arrvlportDtm);
};

/**
 * event
 * @name sbm_retrieve2_submitdone
 * @description
 */
scwin.sbm_retrieve2_submitdone = async function (e) {
    if (e.responseJSON?.resultDataSet?.length && e.responseJSON.resultDataSet[0].Code == -1) {
        return;
    }
    //for=ds_info2
    const rowCnt = ds_info2.getRowCount();
    if (!rowCnt) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002, [""]);  //"조회된 데이터가 없습니다.";
    } else {
        gr_emp2.setFocusedCell(0, 0, false);
        let rowObj;
        let nextRowObj;
        for (let idx = 0; idx < rowCnt - 1; ++idx) {
            rowObj = ds_info2.getRowJSON(idx);
            nextRowObj = ds_info2.getRowJSON(idx + 1);
            if ($c.gus.cfIsNull(nextRowObj.chassisNo)) {
                ds_info2.setCellData(idx + 1, "chassisNo", rowObj.chassisNo);
                ds_info2.setCellData(idx + 1, "chassisEqCd", rowObj.chassisEqCd);
            }
        }
    }
    tbx_totalRows.setValue(rowCnt);
    scwin.startColorChange();
};

