/**
 * method
 * @name setGridReadonly
 * @description
 */
scwin.setGridReadonly = function (readonly) {
    const cols = [
        "cntrNo",
        "sealNo",
        "dptDt",
        "dptHh",
        "arvDt",
        "arvHh",
        "chassisNo",
    ]
    for (let colid of cols) {
        const val = gr_emp2.getReadOnly("column", colid);
        if (val != readonly) {
            gr_emp2.setColumnReadOnly(colid, readonly);
        }
    }
    gr_emp2.setReadOnly("grid", readonly);
};

/**
 * event
 * @name gr_emp2_oncellindexchange
 * @description
 */
scwin.gr_emp2_oncellindexchange = async function (row, col, oldRow, oldColumnIndex) {
    const colid = gr_emp2.getColumnID(col);
    const readOnly = gr_emp2.getReadOnly("grid");
    if (readOnly) {
        return;
    }
    let rowObj;
    if (colid == "dptDt" || colid == "dptHh" || colid == "arvDt" || colid == "arvHh") {
        for (let i = 0; i < row; ++i) {
            rowObj = ds_info2.getRowJSON(i);
            //직도어복화중 실복화단계인 경우 무조건 수정불가.
            if (rowObj.realCmpstcrgYn == "2") {
                //직도어 복화중 최초, 최종인 경우만 입력 가능.
            } else if (rowObj.realCmpstcrgYn == "1") {
            } else if ((rowObj.dptIoMgntYn == 0 && rowObj.dptHh.trim() == "") || (rowObj.arvIoMgntYn == 0 && rowObj.arvHh.trim() == "")) {
                ds_info2.undoRow(row);
                scwin.setGridReadonly(true);
                await $c.gus.cfAlertMsg("이전단계의 실적이 발생하지 않은 상태에서 이후단계의 실적이 발생하면 안됩니다");
                return;
            }
        }
        scwin.setGridReadonly(false);
    }

    rowObj = ds_info2.getRowJSON(row);
    switch (colid) {
        case "cntrNo":
            if (rowObj.selfClsCd == DsConstants.SELF_CLS_CD_MCOM_TRANS) {
                //당사운송인경우
                if (rowObj.dptIoMgntYn == 1 || rowObj.arvIoMgntYn == 1) {
                    ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                    gr_emp2.setColumnReadOnly(colid, true);
                    await $c.gus.cfAlertMsg("당사운송인 경우에는 출도착지 모두 입출고관리대상이 아니어야 합니다");
                    break;
                } else {
                    gr_emp2.setColumnReadOnly(colid, false); //Upper
                }
            } else if (rowObj.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES) {
                //자가영업인경우
                if (rowObj.dptIoMgntYn == 1 && rowObj.arvIoMgntYn == 1) {
                    ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                    gr_emp2.setColumnReadOnly(colid, true);
                    await $c.gus.cfAlertMsg("자가영업인 경우에는 출도착지중 하나는 입출고관리대상이 아니어야 합니다");
                    break;
                } else {
                    gr_emp2.setColumnReadOnly(colid, false); //Upper
                }
            } else {
                if (rowObj.dptIoMgntYn == 1 && rowObj.arvIoMgntYn == 1) {
                    ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                    gr_emp2.setColumnReadOnly(colid, true);
                    await $c.gus.cfAlertMsg("출발, 도착 작업장은 입출고 관리대상 입니다.");
                    break;
                } else {
                    gr_emp2.setColumnReadOnly(colid, false); //Upper
                }
            }
            break;

        case "dptDt":
            if (rowObj.mgntClsYn == 1) {
                gr_emp2.setColumnReadOnly(colid, true);
                await $c.win.alert("관리구분 Y 컨테이너는 입력하실 수 없습니다.");
                break;
            }

            if (rowObj.cntrNo == "") {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                gr_emp2.setColumnReadOnly(colid, true);
                await $c.gus.cfAlertMsg("컨테이너번호가 없습니다");
                break;
            }

            if (rowObj.dptIoMgntYn == 1) {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                gr_emp2.setColumnReadOnly(colid, true);
                break;
            } else {
                if (rowObj.realCmpstcrgYn == "2") {
                    ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                    gr_emp2.setColumnReadOnly(colid, true);
                    break;
                } else if (rowObj.realCmpstcrgYn == "1" && rowObj.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR && rowObj.wrkStpCd == DsConstants.WRK_STP_CD_RETRV) {
                    gr_emp2.setColumnReadOnly(colid, true);
                } else {
                    gr_emp2.setColumnReadOnly(colid, false); //Any
                }
            }
            break;

        case "dptHh":
            if (rowObj.mgntClsYn == 1) {
                gr_emp2.setColumnReadOnly(colid, true);
                await $c.win.alert("관리구분 Y 컨테이너는 입력하실 수 없습니다.");
                break;
            }

            if (rowObj.cntrNo == "") {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                gr_emp2.setColumnReadOnly(colid, true);
                await $c.gus.cfAlertMsg("컨테이너번호가 없습니다");
                break;
            }
            if (rowObj.dptDt == "") {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                gr_emp2.setColumnReadOnly(colid, true);
                await $c.gus.cfAlertMsg("출발일자가 없습니다");
                break;
            }
            if (rowObj.dptIoMgntYn == 1 || rowObj.cntrNo == "") {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                gr_emp2.setColumnReadOnly(colid, true);
                break;
            } else {
                if (rowObj.realCmpstcrgYn == "2") {
                    ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                    gr_emp2.setColumnReadOnly(colid, true);
                    break;
                } else if (rowObj.realCmpstcrgYn == "1" && rowObj.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR && rowObj.wrkStpCd == DsConstants.WRK_STP_CD_RETRV) {
                    gr_emp2.setColumnReadOnly(colid, true);
                } else {
                    gr_emp2.setColumnReadOnly(colid, false); //Any
                }
            }
            if (rowObj.dptWrkPlCd == "6C09" || rowObj.dptWrkPlCd == "6C01") {
                gr_emp2.setColumnReadOnly("dptHh", true);
                gr_emp2.setColumnReadOnly("dptDt", true);
            }
            break;

        case "arvDt":
            if (rowObj.cntrNo == "") {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                gr_emp2.setColumnReadOnly(colid, true);
                await $c.gus.cfAlertMsg("컨테이너번호가 없습니다");
                break;
            }
            if (rowObj.dptDt == "" || rowObj.dptHh == "") {
                if (rowObj.realCmpstcrgYn == "1") {  //직도어 복화중 최초, 최종 단계인 경우.
                    gr_emp2.setColumnReadOnly(colid, false); //Any
                } else if (rowObj.realCmpstcrgYn == "2") {
                    gr_emp2.setColumnReadOnly(colid, true); //직도어 복화중 실복화 단계인 경우 입력불가.
                } else {
                    ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                    gr_emp2.setColumnReadOnly(colid, true);
                    if (rowObj.dptIoMgntYn == 0) {
                        await $c.gus.cfAlertMsg("출발일자를 입력하지 않았습니다");
                    } else {
                        await $c.gus.cfAlertMsg("반출처리가 되지 않았습니다");
                    }
                    break;
                }
            }
            if (rowObj.arvIoMgntYn == 1 || rowObj.cntrNo == "") {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                gr_emp2.setColumnReadOnly(colid, true);
                break;
            } else {
                if (rowObj.realCmpstcrgYn == "2") {
                    gr_emp2.setColumnReadOnly(colid, true); //직도어 복화중 실복화 단계인 경우 입력불가.
                } else
                    gr_emp2.setColumnReadOnly(colid, false); //Any
            }
            break;

        case "arvHh":
            if (rowObj.cntrNo == "") {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                gr_emp2.setColumnReadOnly(colid, true);
                await $c.gus.cfAlertMsg("컨테이너번호가 없습니다");
                break;
            }

            if (rowObj.dptDt == "" || rowObj.dptHh == "") {
                if (rowObj.realCmpstcrgYn == "1") {  //직도어 복화중 최초, 최종 단계인 경우 입력 가능.
                    gr_emp2.setColumnReadOnly(colid, false); //Any
                } else if (rowObj.realCmpstcrgYn == "2") {
                    gr_emp2.setColumnReadOnly(colid, true); //직도어 복화중 실복화 단계인 경우 입력불가.
                } else {
                    ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                    gr_emp2.setColumnReadOnly(colid, true);
                    if (rowObj.dptIoMgntYn == 0) {
                        await $c.gus.cfAlertMsg("출발일자를 입력하지 않았습니다");
                    } else {
                        await $c.gus.cfAlertMsg("반출처리가 되지 않았습니다");
                    }
                    break;
                }
            }
            if (rowObj.arvIoMgntYn == 0 && rowObj.arvDt == "") {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                gr_emp2.setColumnReadOnly(colid, true);
                await $c.gus.cfAlertMsg("도착일자를 입력하지 않았습니다");
                break;
            }

            if (rowObj.arvIoMgntYn == 1 || rowObj.cntrNo == "") {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                gr_emp2.setColumnReadOnly(colid, true);
                break;
            } else {
                if (rowObj.realCmpstcrgYn == "2") {
                    gr_emp2.setColumnReadOnly(colid, true); //직도어 복화중 실복화 단계인 경우 입력불가.
                } else
                    gr_emp2.setColumnReadOnly(colid, false); //Any
            }
            if (rowObj.arvWrkPlCd == "6C09" || rowObj.arvWrkPlCd == "6C01") {
                gr_emp2.setColumnReadOnly("arvHh", true);
                gr_emp2.setColumnReadOnly("arvDt", true);
            }
            break;

        default:
            break;
    }
};

/**
 * event
 * @name gr_emp2_oneditend
 * @params {Number} row
 * @params {Number} col
 * @params {String} value 변경한 값
 * @description asis OnExit(row,colid,olddata)
 * oneditend 이벤트 실행 시점에 datalist에 저장된 값이 olddata에 해당한다.
 */
scwin.gr_emp2_oneditend = async function (row, col, value) {
    value = value.trim();
    const colid = gr_emp2.getColumnID(col);
    let rowObj = ds_info2.getRowJSON(row);
    let rowCnt = null;
    let chkRowObj = null;
    switch (colid) {
        case "cntrNo":
            await scwin.f_cntrSeqSearch(row, value);

            if (!await $c.gus.cfValidate([gr_emp2])) {
                return;
            }

            await scwin.f_retrieveManagementedContainerCnt(value);

            if (ds_chkContainer.getCellData(1, "cd") != "0" && rowObj.odrNo.substring(1, 3) == "C5") {
                await $c.win.alert("컨테이너 " + value + "는 관리구분이 살아있는 컨테이너가 " + ds_chkContainer.getCellData(1, "cd") + "개 있습니다.\n 관리구분을 수정하시고 작업을 진행하십시오.");
                ds_info2.setCellData(row, "cntrNo", "");
                return;
            }

            if (value != "" && value != rowObj.cntrNo) {
                ds_info2.setCellData(row + 1, "cntrNo", value);
            }

            rowCnt = ds_info2.getRowCount();
            for (let i = 0; i < rowCnt - 1; i++) {
                rowObj = ds_info2.getRowJSON(i);
                if (rowObj.cntrNo == "") {
                    continue;
                }
                for (let j = i + 1; j < rowCnt; j++) {
                    chkRowObj = ds_info2.getRowJSON(j);
                    if (chkRowObj.cntrNo == "") {
                        continue;
                    }
                    if (rowObj.wrkPathSeq == chkRowObj.wrkPathSeq) {
                        if (rowObj.odrNo == chkRowObj.odrNo && chkRowObj.cntrNo != rowObj.cntrNo) {
                            await $c.gus.cfAlertMsg((j + 1) + "번째 줄에 같은 작업경로에 다른 컨테이너번호가 있습니다.");
                            ds_info2.setCellData(j, "cntrNo", "");
                            return;
                        }
                    } else {
                        if (chkRowObj.cntrNo !== rowObj.cntrNo) {
                            continue;
                        }

                        if (rowObj.odrNo == chkRowObj.odrNo) {
                            await $c.gus.cfAlertMsg((j + 1) + "번째 줄에 다른 작업경로에 같은 컨테이너번호가 있습니다.");
                            ds_info2.setCellData(j, "cntrNo", "");
                            gr_emp2.refreshColumn("cntrNo");
                            return;
                        }

                        // 복화종류=컴바인 같은 작업경로순번인데 같은 컨테이너번호일 경우.
                        if (rowObj.cmpstcrgKndCd == "CB" && chkRowObj.cmpstcrgKndCd == "CB") {
                            await $c.gus.cfAlertMsg((j + 1) + "번째 줄의 작업지시는 컴바인이므로 컨테이너번호가 달라야 합니다.");
                            ds_info2.setCellData(j, "cntrNo", "");
                            ds_info2.setCellData(j, "dptHh", rowObj.dptHh);
                            ds_info2.setCellData(j, "arvHh", rowObj.arvHh);
                            return;
                        }
                    }
                }
            }

            if (value != "" && !dscommon.cf_CheckCntrNo(value)) {
                if (!await $c.win.confirm((row + 1) + "번째 컨테이너 번호는 유효하지 않은 컨테이너입니다. 계속진행하시겠습니까?")) {
                    return;
                }
            }
            break;
    }
};

/**
 * event
 * @name gr_emp2_onviewchange
 * @description
 */
scwin.gr_emp2_onviewchange = async function (info) {
    let value = info.newValue.trim();
    let row = info.rowIndex;
    const colid = info.colId;
    switch (colid) {
        case "chassisNo":
            if (value != "" && value != info.oldValue) {
                ds_info2.setCellData(row, colid, "");
                await scwin.f_openCommPopUpGrid(2, row, value, "", 'T');
            }
            break;
    }
};

