/**
 * event
 * @name gr_emp2_onafteredit
 * @description
 */
scwin.gr_emp2_onafteredit = async function (row, col, value) {
    const colid = gr_emp2.getColumnID(col);
    let rowObj = ds_info2.getRowJSON(row);
    switch (colid) {
        case "dptHh":
            if (rowObj.dptIoMgntYn == 1) {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                return;
            }
            if (!await $c.gus.cfValidateGrid(gr_emp2, row, colid, gr_emp2.getUserData("gridName"))) {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                break;
            }

            if (rowObj.dptDt != "" && rowObj.dptHh != "") {
                let ret = scwin.chkDateValue(row, rowObj, rowObj.dptDt + rowObj.dptHh, "출발일자");
                if (!ret.success) {
                    await $c.gus.cfAlertMsg(ret.msg);
                    ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                    return;
                }
            }

            if ((ds_info2.getOriginalCellData(row, "dptHh") == "" && rowObj.dptHh.length == 4)) {
                scwin.fillArvDthhCell(row, rowObj);
            }
            break;

        case "dptDt":
            if (rowObj.dptIoMgntYn == 1) {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                return;
            }

            if (!await $c.gus.cfValidateGrid(gr_emp2, row, colid, gr_emp2.getUserData("gridName"))) {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                break;
            }

            if (rowObj.dptDt == "") {
                ds_info2.setCellData(row, "dptHh", "");
            }

            if (rowObj.dptDt != "" && rowObj.dptHh != "") {
                let ret = scwin.chkDateValue(row, rowObj, rowObj.dptDt + rowObj.dptHh, "출발일자");
                if (!ret.success) {
                    await $c.gus.cfAlertMsg(ret.msg);
                    ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                    return;
                }
            }
            break;

        case "arvHh":
            if (rowObj.arvIoMgntYn == 1) {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                return;
            }

            if (!await $c.gus.cfValidateGrid(gr_emp2, row, colid, gr_emp2.getUserData("gridName"))) {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                break;
            }

            if (rowObj.arvDt != "" && rowObj.arvHh != "") {
                let ret = scwin.chkDateValue(row, rowObj, rowObj.arvDt + rowObj.arvHh, "도착일자");
                if (!ret.success) {
                    await $c.gus.cfAlertMsg(ret.msg);
                    ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                    return;
                }
            }
            break;

        case "arvDt":
            if (rowObj.arvIoMgntYn == 1) {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                return;
            }

            if (!await $c.gus.cfValidateGrid(gr_emp2, row, colid, gr_emp2.getUserData("gridName"))) {
                ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                break;
            }

            if (rowObj.arvDt == "") {
                ds_info2.setCellData(row, "arvHh", "");
            }

            if (rowObj.arvDt != "" && rowObj.arvHh != "") {
                let ret = scwin.chkDateValue(row, rowObj, rowObj.arvDt + rowObj.arvHh, "도착일자");
                if (!ret.success) {
                    await $c.gus.cfAlertMsg(ret.msg);
                    ds_info2.setCellData(row, colid, ds_info2.getOriginalCellData(row, colid));
                    return;
                }
            }
            break;

        case "sealNo":
            ds_info2.setCellData(row + 1, "sealNo", rowObj.sealNo);
            break;

        default:
            break;
    }
};

/**
 * method
 * @name chkDateValue
 * @description
 */
scwin.chkDateValue = function (row, rowObj, chkDate, chkDateName) {
    let ret = {
        success: false,
        msg: null,
    };
    if (rowObj.dptDt != "" && rowObj.dptHh != "" && rowObj.arvDt != "" && rowObj.arvHh != "" && (rowObj.dptDt + rowObj.dptHh) >= (rowObj.arvDt + rowObj.arvHh)) {
        ret.msg = "출발일자가 도착일자보다 큽니다";
        return ret;
    }

    let chkRowObj = null;
    for (let idx = 0; idx < row; ++idx) {
        chkRowObj = ds_info2.getRowJSON(idx);
        if (chkRowObj.odrNo != rowObj.odrNo || chkRowObj.cntrSeq != rowObj.cntrSeq) {
            continue;
        }

        if (chkRowObj.dptDt != "" && chkRowObj.dptHh != "" && chkDate <= (chkRowObj.dptDt + chkRowObj.dptHh)) {
            ret.msg = chkDateName + "가 이전단계 출발일자보다 작습니다";
            return ret;
        }
        if (chkRowObj.arvDt != "" && chkRowObj.arvHh != "" && chkDate <= (chkRowObj.arvDt + chkRowObj.arvHh)) {
            ret.msg = chkDateName + "가 이전단계 도착일자보다 작습니다";
            return ret;
        }
    }
    ret.success = true;
    return ret;
};

